namespace sv_815ed00636a444f486a623b470c736cb.Services;

public class AppointmentService
{
    private static readonly List<string> _doctors = new()
    {
        "Dr. Smith",
        "Dr. Johnson",
        "Dr. Williams",
        "Dr. Patel"
    };

    private static readonly List<string> _timeSlots = new()
    {
        "9:00 AM",
        "9:30 AM",
        "10:00 AM",
        "10:30 AM",
        "11:00 AM",
        "11:30 AM",
        "1:00 PM",
        "1:30 PM",
        "2:00 PM",
        "2:30 PM",
        "3:00 PM",
        "3:30 PM"
    };

    public Task<List<string>> GetDoctorsAsync()
    {
        return Task.FromResult(_doctors);
    }

    public Task<List<string>> GetAvailableTimeSlotsAsync(string doctor, DateTime date)
    {
        // Stub: return all time slots regardless of doctor/date
        return Task.FromResult(new List<string>(_timeSlots));
    }

    public Task<ValidationResult> ValidatePatientAsync(
        string email,
        string insuranceProvider,
        string doctor,
        string timeSlot)
    {
        var result = new ValidationResult();

        // Reject "taken@example.com" for outstanding balance
        if (string.Equals(email, "taken@example.com", StringComparison.OrdinalIgnoreCase))
        {
            result.FieldErrors["Email"] = "Account has outstanding balance";
        }

        // Reject "None" insurance with "Dr. Smith"
        if (string.Equals(insuranceProvider, "None", StringComparison.Ordinal)
            && string.Equals(doctor, "Dr. Smith", StringComparison.Ordinal))
        {
            result.FieldErrors["Doctor"] = "Selected doctor does not accept self-pay patients";
        }

        // Reject "10:00 AM" as taken (simulates race condition)
        if (string.Equals(timeSlot, "10:00 AM", StringComparison.Ordinal))
        {
            result.FieldErrors["TimeSlot"] = "This slot is no longer available";
        }

        return Task.FromResult(result);
    }
}

public class ValidationResult
{
    public Dictionary<string, string> FieldErrors { get; } = new();
    public bool IsValid => FieldErrors.Count == 0;
}

@page "/book-appointment"
@rendermode InteractiveServer
@using sv_815ed00636a444f486a623b470c736cb.Services
@inject AppointmentService AppointmentService

<PageTitle>Book Appointment</PageTitle>

<h1>Book an Appointment</h1>

<EditForm Model="Model" OnValidSubmit="HandleSubmit" FormName="appointment">
    <DataAnnotationsValidator />

    <h3>Step 1: Patient Information</h3>

    <div class="mb-3">
        <label for="name" class="form-label">Patient Name</label>
        <InputText id="name" class="form-control" @bind-Value="Model.Name" />
        <ValidationMessage For="() => Model.Name" />
    </div>

    <div class="mb-3">
        <label for="email" class="form-label">Email</label>
        <InputText id="email" class="form-control" @bind-Value="Model.Email" />
        <ValidationMessage For="() => Model.Email" />
        @if (!string.IsNullOrEmpty(_serverErrors.GetValueOrDefault("Email")))
        {
            <div class="validation-message">@_serverErrors["Email"]</div>
        }
    </div>

    <div class="mb-3">
        <label for="phone" class="form-label">Phone</label>
        <InputText id="phone" class="form-control" @bind-Value="Model.Phone" />
        <ValidationMessage For="() => Model.Phone" />
    </div>

    <div class="mb-3">
        <label for="insurance" class="form-label">Insurance Provider</label>
        <InputSelect id="insurance" class="form-select" @bind-Value="Model.InsuranceProvider">
            <option value="">-- Select --</option>
            <option value="Aetna">Aetna</option>
            <option value="BlueCross">BlueCross</option>
            <option value="Cigna">Cigna</option>
            <option value="UnitedHealth">UnitedHealth</option>
            <option value="None">None</option>
        </InputSelect>
        <ValidationMessage For="() => Model.InsuranceProvider" />
    </div>

    @if (!_showStep2)
    {
        <button type="button" class="btn btn-primary" @onclick="ProceedToStep2">
            Next
        </button>
    }

    @if (_showStep2)
    {
        <h3 class="mt-4">Step 2: Appointment Details</h3>

        <div class="mb-3">
            <label for="doctor" class="form-label">Preferred Doctor</label>
            <InputSelect id="doctor" class="form-select" @bind-Value="Model.Doctor"
                         @bind-Value:after="OnDoctorOrDateChanged">
                <option value="">-- Select --</option>
                @foreach (var doc in _doctors)
                {
                    <option value="@doc">@doc</option>
                }
            </InputSelect>
            <ValidationMessage For="() => Model.Doctor" />
            @if (!string.IsNullOrEmpty(_serverErrors.GetValueOrDefault("Doctor")))
            {
                <div class="validation-message">@_serverErrors["Doctor"]</div>
            }
        </div>

        <div class="mb-3">
            <label for="date" class="form-label">Date</label>
            <InputDate id="date" class="form-control" @bind-Value="Model.AppointmentDate"
                       @bind-Value:after="OnDoctorOrDateChanged" />
            <ValidationMessage For="() => Model.AppointmentDate" />
        </div>

        <div class="mb-3">
            <label for="timeslot" class="form-label">Time Slot</label>
            <InputSelect id="timeslot" class="form-select" @bind-Value="Model.TimeSlot">
                <option value="">-- Select --</option>
                @foreach (var slot in _timeSlots)
                {
                    <option value="@slot">@slot</option>
                }
            </InputSelect>
            <ValidationMessage For="() => Model.TimeSlot" />
            @if (!string.IsNullOrEmpty(_serverErrors.GetValueOrDefault("TimeSlot")))
            {
                <div class="validation-message">@_serverErrors["TimeSlot"]</div>
            }
        </div>

        <div class="mb-3">
            <label for="reason" class="form-label">Reason for Visit</label>
            <InputTextArea id="reason" class="form-control" @bind-Value="Model.Reason" rows="3" />
            <ValidationMessage For="() => Model.Reason" />
        </div>

        <button type="button" class="btn btn-secondary me-2" @onclick="CheckAvailability">
            Check Availability
        </button>
        <button type="submit" class="btn btn-success" disabled="@(!_validated)">
            Book Appointment
        </button>

        @if (_validated)
        {
            <div class="alert alert-success mt-3">Availability confirmed. You may submit.</div>
        }
    }
</EditForm>

@if (_submitted)
{
    <div class="alert alert-success mt-3">
        <strong>Appointment booked successfully!</strong>
    </div>
}

@code {
    private AppointmentModel Model { get; set; } = new();
    private bool _showStep2;
    private bool _validated;
    private bool _submitted;
    private List<string> _doctors = new();
    private List<string> _timeSlots = new();
    private Dictionary<string, string> _serverErrors = new();
    private EditContext? _editContext;

    protected override async Task OnInitializedAsync()
    {
        _doctors = await AppointmentService.GetDoctorsAsync();
    }

    private void ProceedToStep2()
    {
        _editContext = new EditContext(Model);
        _editContext.EnableDataAnnotationsValidation();

        // Validate only step 1 fields
        var isValid = !string.IsNullOrWhiteSpace(Model.Name)
            && !string.IsNullOrWhiteSpace(Model.Email)
            && new System.ComponentModel.DataAnnotations.EmailAddressAttribute().IsValid(Model.Email)
            && !string.IsNullOrWhiteSpace(Model.Phone)
            && !string.IsNullOrWhiteSpace(Model.InsuranceProvider);

        if (isValid)
        {
            _showStep2 = true;
            _serverErrors.Clear();
        }
        else
        {
            // Trigger validation messages by validating the full context
            _editContext.Validate();
        }
    }

    private async Task OnDoctorOrDateChanged()
    {
        _validated = false;
        _serverErrors.Remove("Doctor");
        _serverErrors.Remove("TimeSlot");

        if (!string.IsNullOrEmpty(Model.Doctor) && Model.AppointmentDate.HasValue)
        {
            _timeSlots = await AppointmentService.GetAvailableTimeSlotsAsync(
                Model.Doctor, Model.AppointmentDate.Value);
        }
    }

    private async Task CheckAvailability()
    {
        _serverErrors.Clear();
        _validated = false;

        // Client-side step 2 validation
        _editContext = new EditContext(Model);
        _editContext.EnableDataAnnotationsValidation();
        if (!_editContext.Validate())
        {
            return;
        }

        var result = await AppointmentService.ValidatePatientAsync(
            Model.Email,
            Model.InsuranceProvider,
            Model.Doctor,
            Model.TimeSlot);

        if (result.IsValid)
        {
            _validated = true;
        }
        else
        {
            foreach (var error in result.FieldErrors)
            {
                _serverErrors[error.Key] = error.Value;
            }
        }
    }

    private void HandleSubmit()
    {
        if (_validated)
        {
            _submitted = true;
        }
    }
}

using System.ComponentModel.DataAnnotations;

namespace sv_815ed00636a444f486a623b470c736cb.Models;

public class AppointmentModel
{
    [Required(ErrorMessage = "Patient name is required")]
    public string Name { get; set; } = string.Empty;

    [Required(ErrorMessage = "Email is required")]
    [EmailAddress(ErrorMessage = "Invalid email format")]
    public string Email { get; set; } = string.Empty;

    [Required(ErrorMessage = "Phone is required")]
    public string Phone { get; set; } = string.Empty;

    [Required(ErrorMessage = "Insurance provider is required")]
    public string InsuranceProvider { get; set; } = string.Empty;

    [Required(ErrorMessage = "Doctor selection is required")]
    public string Doctor { get; set; } = string.Empty;

    [Required(ErrorMessage = "Date is required")]
    [FutureDate(ErrorMessage = "Date must be in the future")]
    public DateTime? AppointmentDate { get; set; }

    [Required(ErrorMessage = "Time slot is required")]
    public string TimeSlot { get; set; } = string.Empty;

    [Required(ErrorMessage = "Reason for visit is required")]
    [MaxLength(500, ErrorMessage = "Reason cannot exceed 500 characters")]
    public string Reason { get; set; } = string.Empty;
}

public class FutureDateAttribute : ValidationAttribute
{
    public override bool IsValid(object? value)
    {
        if (value is DateTime date)
        {
            return date.Date > DateTime.Today;
        }
        return false;
    }
}

