public class AppointmentService
{
    private static readonly List<string> _doctors = new()
    {
        "Dr. Smith",
        "Dr. Johnson",
        "Dr. Williams",
        "Dr. Patel"
    };

    private static readonly List<string> _timeSlots = new()
    {
        "9:00 AM",
        "9:30 AM",
        "10:00 AM",
        "10:30 AM",
        "11:00 AM",
        "11:30 AM",
        "1:00 PM",
        "1:30 PM",
        "2:00 PM",
        "2:30 PM",
        "3:00 PM",
        "3:30 PM"
    };

    public Task<List<string>> GetDoctorsAsync()
    {
        return Task.FromResult(_doctors);
    }

    public Task<List<string>> GetAvailableTimeSlotsAsync(string doctor, DateTime date)
    {
        // Stub: return all time slots regardless of doctor/date
        return Task.FromResult(new List<string>(_timeSlots));
    }

    public Task<ValidationResult> ValidatePatientAsync(
        string email,
        string insuranceProvider,
        string doctor,
        string timeSlot)
    {
        var result = new ValidationResult();

        // Reject "taken@example.com" for outstanding balance
        if (string.Equals(email, "taken@example.com", StringComparison.OrdinalIgnoreCase))
        {
            result.FieldErrors["Email"] = "Account has outstanding balance";
        }

        // Reject "None" insurance with "Dr. Smith"
        if (string.Equals(insuranceProvider, "None", StringComparison.Ordinal)
            && string.Equals(doctor, "Dr. Smith", StringComparison.Ordinal))
        {
            result.FieldErrors["Doctor"] = "Selected doctor does not accept self-pay patients";
        }

        // Reject "10:00 AM" as taken (simulates race condition)
        if (string.Equals(timeSlot, "10:00 AM", StringComparison.Ordinal))
        {
            result.FieldErrors["TimeSlot"] = "This slot is no longer available";
        }

        return Task.FromResult(result);
    }
}

public class ValidationResult
{
    public Dictionary<string, string> FieldErrors { get; } = new();
    public bool IsValid => FieldErrors.Count == 0;
}
"}

