         if (!Validator.TryValidateObject(Model, context, results, true))
         {
             return;
         }

         var result = await AppointmentService.ValidatePatientAsync(
             Model.Email,
             Model.InsuranceProvider,
             Model.Doctor,
             Model.TimeSlot);

         if (result.IsValid)
         {
             _validated = true;
         }
         else
         {
